{
  "release_id": "release_003",
  "headline": "Release 003 delivers enterprise-grade SAML 2.0 SSO with SCIM provisioning, flexible custom role definitions, and meaningful auth and download performance improvements.",
  "themes": [
    {
      "theme_name": "enterprise-sso",
      "user_facing_summary": "You can now sign in with SAML 2.0 SSO through certified Okta and Azure AD configurations, and provision users automatically via SCIM 2.0 — eliminating manual account setup for IT teams. Per-workspace token rotation policies give security teams the control they need.",
      "supporting_changes": [
        "FEAT-401: SSO via SAML 2.0 — Okta and Azure AD certified configurations",
        "FEAT-410: SCIM 2.0 user provisioning endpoint",
        "DOCS-101: SSO setup guide with screenshots for Okta and Azure AD admins"
      ]
    },
    {
      "theme_name": "custom-roles",
      "user_facing_summary": "Workspace admins can now define their own permission sets instead of choosing from four fixed presets, making it straightforward to match your organization's actual role structure. Existing workspaces keep their current presets until an admin explicitly opts in — no automatic migration.",
      "supporting_changes": [
        "FEAT-402: Workspace-level custom role definitions, replacing the 4 fixed presets"
      ]
    },
    {
      "theme_name": "performance",
      "user_facing_summary": "Auth lookups are now cached, cutting round-trip overhead by ~80% and making login and session checks noticeably faster for high-traffic workspaces. Large file downloads are also quicker — signed-URL generation was moved out of the request path, reducing p99 download latency by ~120ms.",
      "supporting_changes": [
        "PERF-501: Cache session lookups to reduce auth round-trips by ~80%",
        "PERF-505: Move signed-URL generation out of the request hot path"
      ]
    }
  ],
  "notable_changes": [
    "SCIM 2.0 provisioning supports create, update, and deactivate operations; group-based role mapping is planned for a future release.",
    "Token rotation is now configurable per workspace from 1 hour to 24 hours (default: 12 hours).",
    "Download p99 latency reduced by ~120ms after moving signed-URL generation out of the request hot path.",
    "New SSO setup guide with annotated screenshots covers Okta and Azure AD step-by-step for admins new to SAML."
  ],
  "customer_voice": "Enterprise security teams had been waiting on SAML SSO to unblock contract signatures, and IT teams at two prospects required SCIM provisioning before they could adopt the product; customers also called out that auth and large-file download speeds felt sluggish, both of which are directly addressed in this release."
}

